// VEGA v24: Fixed Memory Logic with Binary Output
const items = $input.all();
if (items.length === 0) return [{ json: { error: "No input for memory" } }];

const item = items[0].json;

// 1. Update Technical History (Internal steps)
const history = Array.isArray(item.history) ? item.history : [];
if (item.action_taken) {
    history.push({
      role: "assistant",
      content: `Action: ${item.action_taken}\nResult: ${item.tool_result || 'No Result'}`
    });
}

// 2. Update Chat History (Interaction with user)
let chatHistory = Array.isArray(item.chat_history) ? item.chat_history : [];
if (item.response && item.user_goal) {
    chatHistory.push({
      user: item.user_goal,
      ai: item.response,
      timestamp: new Date().toISOString()
    });
}

// 3. Update Counter
let counter = typeof item.counter === 'number' ? item.counter : 0;
counter++;

// 4. Prepare Binary Content (for history.json)
const content = JSON.stringify(chatHistory.slice(-20), null, 2);

return [{
  json: {
    user_goal: item.user_goal || "No Goal",
    history: history,
    counter: counter,
    chat_history: chatHistory,
    response: item.response || null,
    last_tool_data: item.tool_result_data || null
  },
  binary: {
    data: {
      data: Buffer.from(content).toString('base64'),
      mimeType: 'application/json',
      fileExtension: 'json',
      fileName: 'history.json'
    }
  }
}];

let result = "Success";
let structured_data = null;

if (items.length > 0) {{
  if (items[0].json.id && items[0].json.name) {{
     result = items.map(i => `[FILE] ${i.json.name} (${i.json.id})`).join(", ");
     structured_data = items.map(i => ({{
       id: i.json.id, 
       name: i.json.name, 
       mimeType: i.json.mimeType || 'unknown'
     }}));
  }} 
  else if (items[0].json.hasOwnProperty('stdout')) {{
     result = items[0].json.stdout;
  }}
  else if (items[0].json.hasOwnProperty('stderr')) {{
     result = items[0].json.stderr;
  }}
  else if (items[0].binary) {{
     result = "Binary data processed successfully.";
  }}
  else {{
    result = "Resultado de herramienta no reconocido, pero la operación fue exitosa.";
  }}
}} else {{
  result = "La herramienta se ejecutó pero no produjo ningún resultado (ej. búsqueda sin resultados).";
}}

const prev = $('Clean Actor').last().json;
return [{{ json: {{
  action_taken: prev.accion, 
  tool_result: result,
  tool_result_data: structured_data,
  planner_instruction: prev.instruction, 
  user_goal: prev.user_goal, 
  history: prev.history, 
  counter: prev.counter
}} }}];

